   331→/**
   332→ * Easing functions for smooth animations
   333→ * quadOut provides Google Maps-style smooth deceleration
   334→ */
   335→const Easing = {
   336→  quadOut: (t: number) => t * (2 - t),
   337→  cubicOut: (t: number) => 1 - Math.pow(1 - t, 3),
   338→};
   339→
   340→// Task block dimensions for hit testing (matching MesoLayer)
   341→const TASK_HEIGHT = pxPerTrain - 4;
