  1828→      const dx = (e.clientX - state.viewport.panStart.x) / zoom;
  1829→      const dy = (e.clientY - state.viewport.panStart.y) / zoom;
  1830→
  1831→      // Detect significant movement (F019: to distinguish click from pan)
  1832→      // Using 8px threshold - movement greater than this is a pan, not a click
  1833→      // Higher threshold helps with touchpad/mouse precision issues
  1834→      const moveX = e.clientX - pointerDownPosRef.current.x;
  1835→      const moveY = e.clientY - pointerDownPosRef.current.y;
  1836→      const moveDistance = Math.sqrt(moveX * moveX + moveY * moveY);
  1837→      if (moveDistance > 8) {
  1838→        pointerMovedRef.current = true;
  1839→      }
  1840→
  1841→      const newX = state.viewport.cameraPosAtPanStart.x - dx;
  1842→      const newY = state.viewport.cameraPosAtPanStart.y + dy;
  1843→
  1844→      const clamped = clampCameraToWorld(newX, newY, zoom);
  1845→
