  1851→      const now = performance.now();
  1852→      const worldDx = (e.clientX - lastPointerPosRef.current.x) / zoom;
  1853→      const worldDy = (e.clientY - lastPointerPosRef.current.y) / zoom;
  1854→
  1855→      velocitySamplesRef.current.push({
  1856→        x: worldDx,
  1857→        y: worldDy,
  1858→        time: now,
  1859→      });
  1860→
  1861→      // Keep only recent samples
  1862→      if (velocitySamplesRef.current.length > MOMENTUM_VELOCITY_SAMPLES * 2) {
  1863→        velocitySamplesRef.current = velocitySamplesRef.current.slice(-MOMENTUM_VELOCITY_SAMPLES);
  1864→      }
  1865→
  1866→      lastPointerPosRef.current = { x: e.clientX, y: e.clientY, time: now };
  1867→    },
  1868→    [zoom, clampCameraToWorld, notifyViewportChange, handlePinchZoom, updateHover]
  1869→  );
